     * This method performs the merge sort algorithm on an array of integers.
     * It recursively divides the array into halves, sorts each half, and then merges them.
     * 
     * @param arr The array of non-negative integers to be sorted.
     */
    public static void mergeSort(int[] arr) {
        if (arr == null) {
            throw new IllegalArgumentException("Array cannot be null.");
        }
        if (arr.length < 2) {
            return; // Already sorted
        }
        int mid = arr.length / 2;
        int[] left = Arrays.copyOfRange(arr, 0, mid);
        int[] right = Arrays.copyOfRange(arr, mid, arr.length);

        mergeSort(left); // Sort the left half
        mergeSort(right); // Sort the right half

        merge(arr, left, right); // Merge the two halves
    }

    /**
     * This method merges two sorted arrays into one sorted array.
     * 
     * @param arr The original array that will be merged.
     * @param left The left half of the array, which is already sorted.
